import React, { useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import * as Biometrics from 'expo-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthScreen = () => {
  const authenticateUser = async () => {
    try {
      if (await Biometrics.isSupportedAsync()) {
        const result = await Biometrics.authenticateAsync({
          promptMessage: 'Authenticate with Face ID or Fingerprint',
        });

        if (result.success) {
          await AsyncStorage.setItem('isAuthenticated', 'true');
          // Skip to home screen
          // navigateToHomeScreen();
        } else {
          Alert.alert('Authentication Failed', result.error);
        }
      } else {
        Alert.alert(
          'Biometrics Not Supported',
          'This device does not support biometric authentication.'
        );
      }
    } catch (error) {
      console.error('Error authenticating:', error);
    }
  };

  useEffect(() => {
    const checkAuthentication = async () => {
      const isAuthenticated = await AsyncStorage.getItem('isAuthenticated');
      if (isAuthenticated === 'true') {
        // Skip to home screen
        // navigateToHomeScreen();
      } else {
        authenticateUser();
      }
    };

    checkAuthentication();
  }, []);

  return (
    <View>
      <Text>Welcome!</Text>
      <Button title="Authenticate" onPress={authenticateUser} />
    </View>
  );
};

export default AuthScreen;